[DataContractAttribute]
public class ETGBillExchangeContract extends ERFormatMappingRunBaseContract
{
    public  SalesId         salesId;
    public  CustInvoiceId   salesInvoiceId;
    public  RefRecId        recId;
}

Method.Source:
[
    DataMemberAttribute(identifierStr(CustInvoiceId)),
    SysOperationLabelAttribute(literalstr("Sales Invoice Id")),
    SysOperationHelpTextAttribute(literalstr("Sales Invoice Id"))
]
public CustInvoiceId parmSalesInvoiceId(CustInvoiceId _salesInvoiceId = salesInvoiceId)
{
    salesInvoiceId = _salesInvoiceId;

    return salesInvoiceId;
}

[
    DataMemberAttribute(identifierStr(SalesId)),
    SysOperationLabelAttribute(literalstr("Sales Id")),
    SysOperationHelpTextAttribute(literalstr("Sales Id"))
]
public SalesId parmSalesId(SalesId _salesId = salesId)
{
    salesId = _salesId;

    return salesId;
}

[
    DataMemberAttribute(identifierStr(RefRecId)),
    SysOperationLabelAttribute(literalstr("Cust Invoice RecId")),
    SysOperationHelpTextAttribute(literalstr("Cust Invoice RecId"))
]
public RefRecId parmCustInvoiceRecId(RefRecId _recId = recId)
{
    recId = _recId;

    return recId;
}
